/ Language code (\"en\" for the base guide, else \"fr\", \"es\", …).\n  language  String\n  /// Async generation status: idle | generating | ready | failed. Editor polls.\n  status    String   @default(\"ready\")\n  /// Failure detail when status = failed.\n  error     String?\n  /// Hidden from the public reader until the editor Updates the guide.\n  published Boolean  @default(false)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  segments NarrationSegment[]\n\n  @@unique([guideId, language])\n  @@map(\"narration\")\n}\n\n/// One spoken unit of a narration, anchored to a stable sequence key. `text`\n/// is the source of truth; audio is a derived render (see MediaRender).\nmodel NarrationSegment {\n  id                String    @id @default(uuid())\n  narrationId       String\n  narration         Narration @relation(fields: [narrationId], references: [id], onDelete: Cascade)\n  /// Step.key | slide.key | reserved intro/outro anchors.\n  anchorKey         String\n  /// The spoken script (plain text; provider-neutral).\n  text              String\n  /// Optional provider-neutral structure/overrides (pause, emphasis, style).\n  markup            Json?\n  /// True once a human edits the text — regeneration flags, never overwrites.\n  humanEdited       Boolean   @default(false)\n  /// Hash of the upstream source (localized step/slide text) at write time; a\n  /// mismatch vs. the current guide means this narration is stale.\n  sourceFingerprint String?\n  /// pending | ready | failed.\n  status            String    @default(\"ready\")\n  createdAt         DateTime  @default(now())\n  updatedAt         DateTime  @updatedAt\n\n  renderRefs SegmentRenderRef[]\n\n  @@unique([narrationId, anchorKey])\n  @@map(\"narration_segment\")\n}\n\n/// A content-addressed, immutable render artifact derived from a narration\n/// segment + voice config. `renderHash` is the identity: same inputs → same\n/// row → same R2 object (no re-synthesis). Per-guide namespaced for lifecycle.\nmodel MediaRender {\n  id         String   @id @default(uuid())\n  guideId    String\n  guide      Guide    @relation(fields: [guideId], references: [id], onDelete: Cascade)\n  /// sha256 of (kind, provider, model, voiceId, format, speed, style, payload).\n  renderHash String\n  /// audio (future: avatar-video, export-mp4, podcast).\n  kind       String\n  provider   String\n  model      String?\n  voiceId    String\n  format     String\n  speed      Float?\n  /// Extra provider params captured for reproducibility.\n  params     Json?\n  /// Language code the render belongs to (for pathing/GC; identity is the hash).\n  language   String?\n  /// R2 object key; null until status = ready.\n  r2Key      String?\n  durationMs Int?\n  sizeBytes  Int?\n  /// pending | ready | failed.\n  status     String   @default(\"pending\")\n  error      String?\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  refs SegmentRenderRef[]\n\n  @@unique([guideId, renderHash])\n  @@index([guideId, status])\n  @@map(\"media_render\")\n}\n\n/// Which render a narration segment currently resolves to, per media kind.\n/// Separating this from the segment (script) and the render (artifact) keeps\n/// three lifecycles clean and lets multiple kinds coexist per segment.\nmodel SegmentRenderRef {\n  id        String           @id @default(uuid())\n  segmentId String\n  segment   NarrationSegment @relation(fields: [segmentId], references: [id], onDelete: Cascade)\n  /// audio (future kinds share the segment).\n  kind      String\n  renderId  String\n  render    MediaRender      @relation(fields: [renderId], references: [id], onDelete: Cascade)\n  createdAt DateTime         @default(now())\n  updatedAt DateTime         @updatedAt\n\n  @@unique([segmentId, kind])\n  @@map(\"segment_render_ref\")\n}\n",
